import React, { useState } from 'react';
import { FaBars, FaTimes } from 'react-icons/fa';
import logo from '../Assets/logo.png';
import './index.css';

const Header = () => {

    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    const toggleMobileMenu = () => {
        setIsMobileMenuOpen(!isMobileMenuOpen);
    };

    return (
        <header className="bg-[#1c274c] p-4">
            <div className="container mx-auto flex justify-between items-center">
                <div className="flex items-center">
                    <img src={logo} alt="Crib Cleaners" className="h-8 w-auto mr-2" />
                </div>
                <div className="hidden md:flex space-x-8 ml-2 mr-4 text-white font-semibold text-base tracing-wider uppercase">
                    <a href="#home" className="hover:underline">Home</a>
                    <a href="#services" className="hover:underline">Services</a>
                    <a href="#about" className="hover:underline">About</a>
                    <a href="#contact" className="hover:underline">Contact</a>
                </div>
                <div className="md:hidden">
                    <button onClick={toggleMobileMenu} className="text-white focus:outline-none">
                        {isMobileMenuOpen ? <FaTimes size={24} /> : <FaBars size={24} />}
                    </button>
                </div>
            </div>
            {isMobileMenuOpen && (
                 <div className={`fixed inset-0 bg-black mt-16 flex flex-col items-center justify-start z-50 transform ${isMobileMenuOpen ? 'translate-x-0' : 'translate-x-full'} transition-transform duration-300`}>
                 <ul className="space-y-6 text-white font-semibold text-xl tracking-wider uppercase">
                     <li style={{ transitionDelay: '0.2s' }} className={`transition-opacity duration-500 ${isMobileMenuOpen ? 'opacity-100' : 'opacity-0'}`}>
                         <a href="#home" className="hover:underline" onClick={toggleMobileMenu}>Home</a>
                     </li>
                     <li style={{ transitionDelay: '0.4s' }} className={`transition-opacity duration-500 ${isMobileMenuOpen ? 'opacity-100' : 'opacity-0'}`}>
                         <a href="#services" className="hover:underline" onClick={toggleMobileMenu}>Services</a>
                     </li>
                     <li style={{ transitionDelay: '0.6s' }} className={`transition-opacity duration-500 ${isMobileMenuOpen ? 'opacity-100' : 'opacity-0'}`}>
                         <a href="#about" className="hover:underline" onClick={toggleMobileMenu}>About</a>
                     </li>
                     <li style={{ transitionDelay: '0.8s' }} className={`transition-opacity duration-500 ${isMobileMenuOpen ? 'opacity-100' : 'opacity-0'}`}>
                         <a href="#contact" className="hover:underline" onClick={toggleMobileMenu}>Contact</a>
                     </li>
                 </ul>
             </div>
             )}
        </header>
    );
};

export default Header;
